'use client';

import {Button} from '@/components/ui/button';
import {Input} from '@/components/ui/input';
import {Label} from '@/components/ui/label';
import {cn} from '@/lib/utils';

import {Check, Copy} from 'lucide-react';
import * as React from 'react';

type CopyableFieldProps = {
  /** The text value to display and copy */
  value: string;
  /** Accessible label for the field */
  label: string;
  /** Hide the label visually (still accessible) @default false */
  hideLabel?: boolean;
  /** Callback fired after successful copy */
  onCopy?: () => void;
  className?: string;
};

function CopyableField({
  value,
  label,
  hideLabel = false,
  onCopy,
  className,
}: CopyableFieldProps) {
  const [copied, setCopied] = React.useState(false);
  const id = React.useId();

  React.useEffect(() => {
    if (!copied) return;
    const timer = setTimeout(() => setCopied(false), 2000);
    return () => clearTimeout(timer);
  }, [copied]);

  const handleCopy = React.useCallback(async () => {
    try {
      const writePromise = navigator.clipboard.writeText(value);
      setCopied(true);
      await writePromise;
      onCopy?.();
    } catch {
      setCopied(false);
      console.error('[CopyableField] Failed to copy to clipboard');
    }
  }, [value, onCopy]);

  return (
    <div className={cn('flex flex-col gap-1.5', className)}>
      <Label htmlFor={id} className={cn(hideLabel ? 'sr-only' : undefined)}>
        {label}
      </Label>
      <div className="flex items-center gap-2">
        <Input
          id={id}
          readOnly
          value={value}
          className="font-mono text-sm"
          aria-label={label}
        />
        <Button
          type="button"
          variant="outline"
          size="icon"
          aria-label={copied ? 'Copied!' : `Copy ${label}`}
          onClick={handleCopy}
          className="shrink-0"
        >
          {copied ? (
            <Check className="h-4 w-4 text-success" />
          ) : (
            <Copy className="h-4 w-4" />
          )}
        </Button>
      </div>
    </div>
  );
}

export {CopyableField};
export type {CopyableFieldProps};
